import { createRouter, createWebHistory } from 'vue-router'
import Home from '../pages/Home.vue'

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home,
    meta: {
      title: 'Home | Portfolio Jee ',
     }
  },
  {
    path: '/growee',
    name: 'Growee',
    component: () => import('../pages/projects/Growee.vue'),
    meta: {
      title: 'Growee | Portfolio Jee',
     }
  },
  {
    path: '/lawyer-consultation-report',
    name: 'Lawyer',
    component: () => import('../pages/projects/Lawyer.vue'),
    meta: {
      title: 'Lawyer Consultation Report | Portfolio Jee',
     }
  }
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
  scrollBehavior() {
    return { top: 0 }
  },
})

router.beforeEach((toRoute, fromRoute, next) => {
  window.document.title = toRoute.meta && toRoute.meta.title ? toRoute.meta.title : 'Home';
  next();
})
export default router