  },
  mounted () {
    window.addEventListener('scroll', this.handleScroll);
  },
  unmounted () {
    window.removeEventListener('scroll', this.handleScroll);
  },
  methods: {
    convertRange( value, r1, r2 ) { 
        return ( value - r1[ 0 ] ) * ( r2[ 1 ] - r2[ 0 ] ) / ( r1[ 1 ] - r1[ 0 ] ) + r2[ 0 ];
    },
    move(element, scroll, start, finish){
      var el = element;
      el.style.animationFillMode = "none";
      var progress = this.convertRange(scroll,[0,600],[0,100]);
      var pos = {
        x: 0,
        y: 0,
        z: 0
      };
      var deg = {
        x: 0,
        y: 0,
        z: 0
      };
      pos["x"] = this.convertRange(progress,[0,100],[start["pos"]["x"],finish["pos"]["x"]]);
      pos["y"] = this.convertRange(progress,[0,100],[start["pos"]["y"],finish["pos"]["y"]]);
      pos["z"] = this.convertRange(progress,[0,100],[start["pos"]["z"],finish["pos"]["z"]]);
      deg["x"] = this.convertRange(progress,[0,100],[start["deg"]["x"],finish["deg"]["x"]]);
      deg["y"] = this.convertRange(progress,[0,100],[start["deg"]["y"],finish["deg"]["y"]]);
      deg["z"] = this.convertRange(progress,[0,100],[start["deg"]["z"],finish["deg"]["z"]]);

      el.style.opacity = this.convertRange(progress,[0,100],[1,0]);
      el.style.filter = "blur("+this.convertRange(progress,[0,100],[0,20])+"px)";
      el.style.transform = "translate3d("+ pos["x"] +"px, "+ pos["y"] +"px, "+ pos["z"] +"px) rotateX("+ deg["x"] +"deg) rotateY("+deg["y"]+"deg) rotateZ("+deg["z"] +"deg)";
