<template>
    <div @mouseenter="mouseEnter" @mousemove="mouseMove" @mouseleave="mouseLeave" id="tilt" class="container group bg-slate-800 w-full relative overflow-hidden rounded-2xl border border-transparent border-t-slate-700">
        <slot/>
    </div>
</template>

<style scoped>
#tilt{
    transition: transform 100ms ease-out;
}
</style>

<script>
export default {
  components: {
  },
  props: {
  },
  methods : {
    mouseEnter(event) {
      event.currentTarget.addEventListener('mousemove', this.mouseMove);
    },
    mouseLeave(event) {
      event.currentTarget.style.transform = `perspective(500px) rotateY(0deg) rotateX(0deg) scale3d(1, 1, 1)`;
      event.currentTarget.removeEventListener('mousemove', this.mouseMove);
    },
    mouseMove(event) {
      var el = document.getElementById("tilt");
      const multiplier = 5;
      var { top, bottom, left, right } = el.getBoundingClientRect();

      const middleX = (right - left) / 2;
      const middleY = (bottom - top) / 2;

      const clientX = event.offsetX;
      const clientY = event.offsetY;

      const offsetX = (clientX - middleX) / middleX;
      const offsetY = (middleY - clientY) / middleY;

      event.currentTarget.style.transform = `perspective(1000px) rotateY(${offsetX *multiplier}deg) rotateX(${offsetY * multiplier}deg) scale3d(1, 1, 1)`;
    }
  }
}
</script>
